// Absage-Payload normalisieren
const body = $input.first().json.body || $input.first().json;

const datum     = body.datum      || body.Datum      || '';
const zeit      = body.zeit       || body.Zeit       || body.Uhrzeit || '';
const fahrlehrer = body.fahrlehrer || body.Fahrlehrer || '';
const art       = body.art        || body.Art        || 'Fahrstunde';
const abgesagtVon  = body.schueler || body.Schueler || body.name || '';
const quelle    = body.quelle     || 'manuell';
let   abgesagtTelefon = (body.telefon || body.Telefon || '').toString();

abgesagtTelefon = abgesagtTelefon.replace(/[\s\-\/\(\)]/g, '');
if (abgesagtTelefon && !abgesagtTelefon.startsWith('+')) {
  abgesagtTelefon = '+49' + abgesagtTelefon.replace(/^0/, '');
}

const slotId = `${datum}_${zeit.replace(':','')}_ ${fahrlehrer}`.replace(/\s+/g, '_');

return [{ json: { datum, zeit, fahrlehrer, art, abgesagtVon, abgesagtTelefon, slotId, quelle, timestamp: new Date().toISOString() } }];

// Top-3 passende Schueler von der Warteliste ermitteln
const warteliste = $('Warteliste laden').all();
const slot = $('Absage normalisieren').first().json;

const kandidaten = [];

for (const item of warteliste) {
  const d = item.json;
  const status = (d.Status || '').toLowerCase();
  if (status === 'gebucht' || status === 'abgesagt' || status === 'abgelaufen') continue;

  const name = d.Schueler || d.Name || '';
  let telefon = (d.Telefon || '').toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) telefon = '+49' + telefon.replace(/^0/, '');
  if (!name || !telefon) continue;

  const wunschTage   = (d.Wunsch_Tage   || '').toLowerCase();
  const wunschLehrer = (d.Fahrlehrer    || '').toLowerCase();
  const prioritaet   = parseInt(d.Prioritaet || '5', 10);

  // Score-System: je hoeher, desto bevorzugter
  let score = 10 - Math.min(prioritaet, 9);

  // Bonus: Wunsch-Fahrlehrer stimmt ueberein
  if (wunschLehrer && slot.fahrlehrer && slot.fahrlehrer.toLowerCase().includes(wunschLehrer)) score += 5;

  // Bonus: Wunschtag stimmt ueberein (grober Check)
  if (wunschTage && slot.datum) {
    const wochentage = ['montag','dienstag','mittwoch','donnerstag','freitag','samstag'];
    const slotTag = new Date(slot.datum).getDay(); // 0=So, 1=Mo ...
    const tagName = wochentage[slotTag - 1] || '';
    if (tagName && wunschTage.includes(tagName)) score += 3;
  }

  kandidaten.push({ json: { schuelerName: name, schuelerTelefon: telefon, score, rowIndex: d.row_number || 0, ...slot } });
}

kandidaten.sort((a, b) => b.json.score - a.json.score);
const top3 = kandidaten.slice(0, 3);

return top3.length > 0 ? top3 : [{ json: { skip: true, ...slot } }];

