// Abgelaufene Angebote finden (Status=angeboten AND Ablauf_um < jetzt)
const logItems = $input.all();
const now = new Date();
const abgelaufen = [];

// Alle Slot-IDs mit abgelaufenen Angeboten sammeln
const slotMap = {}; // slotId -> { items: [], allAbgelaufen: bool }

for (const item of logItems) {
  const d = item.json;
  if ((d.Status || '').toLowerCase() !== 'angeboten') continue;

  const ablaufStr = d.Ablauf_um || '';
  if (!ablaufStr) continue;

  let ablauf;
  try { ablauf = new Date(ablaufStr); } catch(e) { continue; }
  if (isNaN(ablauf.getTime())) continue;

  const istAbgelaufen = ablauf < now;
  const slotId = d.Slot_ID || '';

  if (!slotMap[slotId]) slotMap[slotId] = { items: [], hatAktives: false };
  slotMap[slotId].items.push({ ...d, istAbgelaufen, rowIndex: item.json.row_number || 0 });
  if (!istAbgelaufen) slotMap[slotId].hatAktives = true;
}

// Nur Slots bei denen ALLE Angebote abgelaufen und keiner JA gesagt hat
const results = [];
for (const [slotId, data] of Object.entries(slotMap)) {
  if (data.hatAktives) continue; // Noch aktive Angebote vorhanden
  const hatJa = data.items.some(i => (i.Status || '').toLowerCase() === 'angenommen');
  if (hatJa) continue; // Jemand hat schon JA gesagt

  const hatAbgelaufen = data.items.some(i => i.istAbgelaufen);
  if (!hatAbgelaufen) continue;

  // Erstes Item als Repräsentant nehmen
  const repr = data.items[0];
  const schonAlarmiert = data.items.some(i => (i.Status || '').toLowerCase() === 'abgelaufen_alarmiert');
  if (schonAlarmiert) continue;

  results.push({
    json: {
      slotId,
      datum: repr.Datum,
      zeit: repr.Zeit,
      art: repr.Art,
      fahrlehrer: repr.Fahrlehrer,
      anzahlKontaktiert: data.items.length
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];

