// JA / NEIN Response des Schuelers verarbeiten
const body = $input.first().json.body || $input.first().json;
const from = (body.From || body.from || '').replace('whatsapp:', '').trim();
const msg  = (body.Body || body.body || '').trim().toUpperCase();

const hatJa   = msg === 'JA' || msg === 'YES' || msg === 'OK';
const hatNein = msg === 'NEIN' || msg === 'NO' || msg === 'NEIN DANKE';

return [{ json: { from, msg, hatJa, hatNein } }];
